var TechnicalNameGenerator={initialize:function(e,t){var n=document.getElementById(e),i=document.getElementById(t);if(n&&i){var a=""!==i.value.trim();i.addEventListener("input",function(){a=""!==i.value.trim()}),n.addEventListener("input",function(){!a&&(i.value=(n.value||"").trim().split(/[^A-Za-z0-9]+/).filter(function(e){return e.length>0}).map(function(e){return e.toLowerCase()}).join("-"))})}}};
